package com.google.gson.metrics;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.File;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.io.Reader;
import java.io.StringWriter;
import java.lang.reflect.Method;
import java.net.URL;
import java.util.zip.ZipEntry;
import java.util.zip.ZipFile;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

public class ParseBenchmarkTest {

  private static final String ZIP_RESOURCE_PATH = "/ParseBenchmarkData.zip";
  private static final String TEST_FILE_NAME = "test.json";
  private static final String TEST_CONTENT = "{\"key\":\"value\"}";

  private Method resourceToStringMethod;

  // Helper subclass to override getResourceFile to avoid URI issues
  public static class ParseBenchmarkTestSubclass extends ParseBenchmark {
    private static File getResourceFile(String path) {
      return new File("dummy.zip");
    }

    public static String resourceToStringTest(String fileName) throws Exception {
      // Call the original resourceToString but override getResourceFile by reflection
      // We'll invoke the original resourceToString method via reflection
      Method resourceToStringMethod = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
      resourceToStringMethod.setAccessible(true);
      return (String) resourceToStringMethod.invoke(null, fileName);
    }
  }

  @BeforeEach
  public void setUp() throws Exception {
    resourceToStringMethod = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
    resourceToStringMethod.setAccessible(true);
  }

  @Test
  public void testResourceToString_readsContentFromZipEntry() throws Exception {
    try (MockedConstruction<ZipFile> mockedZipFile = Mockito.mockConstruction(ZipFile.class,
        (mock, context) -> {
          ZipEntry zipEntry = new ZipEntry(TEST_FILE_NAME);
          when(mock.getEntry(TEST_FILE_NAME)).thenReturn(zipEntry);

          InputStream inputStream = new ByteArrayInputStream(TEST_CONTENT.getBytes());
          when(mock.getInputStream(zipEntry)).thenReturn(inputStream);

          doNothing().when(mock).close();
        })) {

      // Use reflection to temporarily replace getResourceFile method in ParseBenchmark via a spy
      Method getResourceFileMethod = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
      getResourceFileMethod.setAccessible(true);

      // Use reflection to replace getResourceFile temporarily by using a proxy is complicated,
      // so we use a trick: temporarily replace the method by a lambda using MethodHandles
      // but since it's complicated, we use a workaround:
      // We create a subclass with a public static method that calls resourceToString,
      // and override getResourceFile in that subclass.

      // Instead, since resourceToString is static and calls getResourceFile static private,
      // we cannot override it easily.
      // So instead, we use a workaround: mock ZipFile constructor and rely on that.

      // The simplest fix is to mock ZipFile constructor and also mock getResourceFile by temporarily replacing the method with a lambda using MethodHandles.

      // But since MethodHandles cannot replace method body easily without instrumentation,
      // we will use Java 9+ reflection hack to replace the method temporarily.

      // So here, we use a temporary hack: replace the method temporarily via reflection.

      // Save original accessibility and modifiers of getResourceFile
      // Using reflection to replace private static method is complicated and unsafe,
      // so instead, we use the following hack: use a custom classloader or instrumentation,
      // but it's out of scope.

      // Therefore, we just mock ZipFile constructor and rely on that.

      // Now invoke the original resourceToString method, which calls getResourceFile,
      // which will fail unless the resource exists.
      // So instead, we temporarily mock getResourceFile by using a spy on ParseBenchmark class.

      // Since Mockito 3 without inline mocking cannot mock static methods,
      // we use reflection to temporarily replace getResourceFile method.

      // Instead, we create a helper method in this test class to call resourceToString with mocked ZipFile.

      // So finally, just invoke resourceToStringMethod with TEST_FILE_NAME and rely on mocked ZipFile constructor.

      String result = (String) resourceToStringMethod.invoke(null, TEST_FILE_NAME);

      assertEquals(TEST_CONTENT, result);
    }
  }

  @Test
  public void testResourceToString_closesZipFileOnException() throws Exception {
    try (MockedConstruction<ZipFile> mockedZipFile = Mockito.mockConstruction(ZipFile.class,
        (mock, context) -> {
          when(mock.getEntry(TEST_FILE_NAME)).thenThrow(new IOException("forced exception"));
          doNothing().when(mock).close();
        })) {

      Exception thrown = assertThrows(Exception.class, () -> {
        resourceToStringMethod.invoke(null, TEST_FILE_NAME);
      });

      assertFalse(mockedZipFile.constructed().isEmpty(), "No ZipFile instances constructed");
      ZipFile mockZipFile = mockedZipFile.constructed().get(0);
      verify(mockZipFile).close();

      assertTrue(thrown.getCause() instanceof IOException);
      assertEquals("forced exception", thrown.getCause().getMessage());
    }
  }

}
